from collections import defaultdict, deque

def detect_circular_delegation(session_history):
    graph = defaultdict(list)
    for step in session_history:
        if 'delegation' in step:
            graph[step['from_agent']].append(step['to_agent'])

    visited = set()
    rec_stack = set()

    def dfs(node):
        visited.add(node)
        rec_stack.add(node)
        for neighbor in graph[node]:
            if neighbor not in visited:
                if dfs(neighbor):
                    return True
            elif neighbor in rec_stack:
                return True
        rec_stack.remove(node)
        return False

    for node in graph:
        if node not in visited:
            if dfs(node):
                return {'issue': 'CIRCULAR_DELEGATION', 'cycle_detected': True}
    return {'issue': 'CIRCULAR_DELEGATION', 'cycle_detected': False}

from google.adk import Agent

def check_model_consistency(workflow_agents):
    model_configs = {}
    for agent_name, agent in workflow_agents.items():
        if hasattr(agent, 'model'):
            model_key = f"{agent.model.name}:{agent.model.temperature}"
            model_configs[agent_name] = model_key

    if len(set(model_configs.values())) > 1:
        return {
            'issue': 'MODEL_INCONSISTENCY',
            'models_used': model_configs,
            'is_consistent': False
        }
    return {'issue': 'MODEL_INCONSISTENCY', 'is_consistent': True}

import hashlib

def monitor_session_state(session):
    state_snapshots = []
    initial_hash = hashlib.md5(str(session.state).encode()).hexdigest()

    for turn in session.turn_history:
        current_hash = hashlib.md5(str(turn.state).encode()).hexdigest()
        state_snapshots.append({
            'turn': len(state_snapshots),
            'hash': current_hash,
            'size': len(str(turn.state))
        })

    corruption_detected = any(s['size'] > 10000 for s in state_snapshots)  # Threshold for bloat
    return {
        'issue': 'STATE_CORRUPTION',
        'initial_hash': initial_hash,
        'snapshots': state_snapshots,
        'corrupted': corruption_detected
    }
